from openpyxl import load_workbook
wb = load_workbook('budget.xlsx')
terms = ['climate', 'sustainability', 'diversity', 'inclusion']
found = []
for sheet_name in wb.sheetnames:
    sheet = wb[sheet_name]
    for row in sheet.iter_rows():
        for cell in row:
            if cell.value and isinstance(cell.value, str):
                for term in terms:
                    if term.lower() in cell.value.lower():
                        found.append(f'{sheet_name}!{cell.coordinate}: {cell.value}')
print('Found original terms:')
for f in found:
    print(f)
